class {{nama_class}}:
    """CORS header generator.
    Returns dict of headers to add to HTTP response.
    """
    def __init__(self, allowed_origins=None, allowed_methods=None, allowed_headers=None, max_age=86400):
        self.allowed_origins = allowed_origins or ['{{default_origin}}']
        self.allowed_methods = allowed_methods or ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS']
        self.allowed_headers = allowed_headers or ['Content-Type', 'Authorization']
        self.max_age = max_age

    def _origin_allowed(self, origin):
        if '*' in self.allowed_origins:
            return True
        return origin in self.allowed_origins

    def get_headers(self, request_origin=None):
        """Generate CORS headers based on request origin."""
        headers = {}
        if request_origin and self._origin_allowed(request_origin):
            headers['Access-Control-Allow-Origin'] = request_origin
            headers['Vary'] = 'Origin'
        elif '*' in self.allowed_origins:
            headers['Access-Control-Allow-Origin'] = '*'
        else:
            return {}
        headers['Access-Control-Allow-Methods'] = ', '.join(self.allowed_methods)
        headers['Access-Control-Allow-Headers'] = ', '.join(self.allowed_headers)
        headers['Access-Control-Max-Age'] = str(self.max_age)
        return headers

    def get_preflight_headers(self, request_origin=None):
        """Headers for OPTIONS preflight response."""
        return self.get_headers(request_origin)

class {{nama_exception}}(Exception):
    """Raised when request validation fails."""
    def __init__(self, errors):
        self.errors = errors
        super().__init__(str(errors))


class {{nama_class}}:
    """Validate request data against a simple schema.
    Schema format: {'field_name': {'type': str, 'required': True, 'min': 0, 'max': 100}}
    """
    TYPE_MAP = {'str': str, 'int': int, 'float': float, 'bool': bool, 'list': list, 'dict': dict}

    def __init__(self, schema):
        self.schema = schema

    def validate(self, data):
        """Validate data against schema. Raise ValidationError if invalid.
        Returns cleaned data dict.
        """
        errors = []
        cleaned = {}
        for field, rules in self.schema.items():
            required = rules.get('required', False)
            expected_type = rules.get('type')
            if field not in data:
                if required:
                    errors.append({'field': field, 'error': 'required'})
                continue
            value = data[field]
            if expected_type:
                type_cls = self.TYPE_MAP.get(expected_type, expected_type)
                if not isinstance(value, type_cls):
                    errors.append({'field': field, 'error': 'type', 'expected': expected_type, 'got': type(value).__name__})
                    continue
            if 'min' in rules and isinstance(value, (int, float)) and value < rules['min']:
                errors.append({'field': field, 'error': 'min', 'min': rules['min']})
            if 'max' in rules and isinstance(value, (int, float)) and value > rules['max']:
                errors.append({'field': field, 'error': 'max', 'max': rules['max']})
            if 'min_length' in rules and isinstance(value, str) and len(value) < rules['min_length']:
                errors.append({'field': field, 'error': 'min_length', 'min': rules['min_length']})
            if 'max_length' in rules and isinstance(value, str) and len(value) > rules['max_length']:
                errors.append({'field': field, 'error': 'max_length', 'max': rules['max_length']})
            if 'choices' in rules and value not in rules['choices']:
                errors.append({'field': field, 'error': 'choices', 'allowed': rules['choices']})
            cleaned[field] = value
        if errors:
            raise {{nama_exception}}(errors)
        return cleaned
